method merge_settings_impl(
  defaults: map<string, string>,
  file_config: map<string, string>, 
  env: map<string, string>
) returns (result: map<string, string>)
{
  // Start with defaults
  result := defaults;

  // Apply file_config (higher precedence than defaults)
  var fc_keys := file_config.Keys;
  while fc_keys != {}
    decreases |fc_keys|
  {
    var k :| k in fc_keys;
    result := result[k := file_config[k]];
    fc_keys := fc_keys - {k};
  }

  // Apply env vars (highest precedence)
  var env_keys := env.Keys;
  while env_keys != {}
    decreases |env_keys|
  {
    var k :| k in env_keys;
    if |k| >= 5 && k[0..5] == "APP__" {
      var rest := k[5..];
      result := result[rest := env[k]];
    }
    env_keys := env_keys - {k};
  }
}

method Main() {
  var r := merge_settings_impl(
    map["port" := "8080", "debug" := "false"],
    map["port" := "9090"],
    map["APP__DEBUG" := "true", "APP__HOST__NAME" := "localhost"]
  );
  print r, "\n";
